//! Phase 2 — CERTIFIED AGENCY: what Thoth can DO, derived from what he can PROVE.
//!
//! This lifts third-eye from "what is this object's certified dynamical regime" (object_intel) to the
//! PRESCRIPTIVE question Thoth's body asks: "given the certified profile, which manual affordance —
//! grasp / push / drop — is admissible, and which does the evidence DECLINE or ABSTAIN?" It is the
//! same §7.5 admission discipline as `physics.rs` / `object_intel.rs`: every clause is `accept` /
//! `abstain` / `decline` and cites a green, Init-only, zero-axiom gnosis-math law. third-eye runs NO
//! force solver and NO ML; an affordance is a GATE on the already-certified profile, never a planner.
//!
//! THE C2-SHADOW GATE MADE PRESCRIPTIVE (the load-bearing idea): `object_intel`'s `abstain_reason`
//! already tells us WHY a body is not a clean free rigid body. Here that read becomes a precondition
//! for ACTING: Thoth only acts on a CLEAN abstain_reason. A `NonRigidActuated` read (the kinematic
//! fingerprint of a deforming / muscle-actuated body — e.g. a grabbing hand) ABSTAINS the grasp: you
//! do not grab a hand. An `AliasedUnreliable` read ABSTAINS too: you do not act on an unreliable
//! measurement. This is honest agency — derive the affordance from the certificate, abstain otherwise.
//!
//! HONEST BOUNDS (same contract as object_intel): EVERYTHING IS RELATIVE. `hand_reach` and
//! `max_impulse` are in the SAME relative units as the profile's `char_size` and `momentum` (no
//! absolute SI — see object_intel header). So a `Decline` ("too big to grasp", "too much momentum to
//! arrest") is a RELATIVE, within-scene structural verdict, not an absolute kg / metre claim. The
//! certified output is the STRUCTURE — which affordance is admissible and the law that gates it.
//!
//! Laws pinned (all green, Init-only, zero-axiom; same provenance as object_intel.rs):
//!  - grasp conserves momentum via contact: `ForkRaceFoldVentAreForces.lean:49` `fork_preserves_charge`
//!    — a grasp is a contact that arrests the body's momentum; the impulse to stop it is exactly its
//!    momentum |p| (the conserved quantity transported into Thoth's hand). The affordance is admitted
//!    only when that impulse is within reach; the conservation law is the one the arrest must satisfy.
//!  - causal bound (reused indirectly via the profile's regime, which already gated `velocity_causal`
//!    under `AckermannLightConeBridge.subluminal_never_reaches_front`).

use crate::object_intel::{AbstainReason, Regime, RigidProfile};
use crate::physics::Verdict;

const LAW_GRASP: &str = "ForkRaceFoldVentAreForces.fork_preserves_charge";

/// The green gnosis-math law a certified `PossibleGrab` predicate is tagged with (re-exported so
/// `SceneModel` can law-tag the emitted predicate). A grasp arrests the conserved momentum via contact.
pub const GRASP_LAW: &str = LAW_GRASP;

/// The kind of manual affordance an object's certified profile admits. A single object may admit
/// several (a small at-rest cup is Graspable AND Pushable AND Droppable-once-held); the assessor
/// reports the PRIMARY affordance with the strongest certified support, plus the gate that bounds it.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum AffordanceKind {
    /// Thoth can close a hand around it and arrest its momentum (size within reach, impulse-to-stop
    /// within budget, regime stable, abstain_reason clean).
    Graspable,
    /// Thoth can apply a lateral contact impulse to set it moving (admissible when it is graspable
    /// reach-wise but the body is already in free motion — a push redirects, not arrests).
    Pushable,
    /// Thoth can release a held body and let it fall freely (the at-rest / free-translation
    /// continuation the conservation law already certifies — the inverse of a grasp).
    Droppable,
}

impl AffordanceKind {
    pub fn as_str(self) -> &'static str {
        match self {
            AffordanceKind::Graspable => "graspable",
            AffordanceKind::Pushable => "pushable",
            AffordanceKind::Droppable => "droppable",
        }
    }
}

/// A certified (or held / declined) manual affordance for one object. Mirrors `object_intel::DynVerdict`
/// / `physics::FactVerdict`: a verdict + the law it was gated under + a human reason.
#[derive(Debug, Clone)]
pub struct GraspAffordance {
    /// The object this affordance is about (the profile's track id).
    pub id: u64,
    /// The affordance kind the gate resolved to (the primary admissible action, or the kind that was
    /// declined / abstained — `kind` is meaningful with `verdict` together).
    pub kind: AffordanceKind,
    /// §7.5 verdict: Accept = a certified-admissible affordance; Decline = the geometry/impulse bars
    /// it (too big / too much momentum); Abstain = the regime/abstain_reason makes acting unsafe.
    pub verdict: Verdict,
    /// The green gnosis-math law the affordance is gated under (the conservation the arrest satisfies).
    pub law: &'static str,
    /// Human-readable reason (the gate clause that decided the verdict).
    pub reason: String,
    /// Confidence in [0,1]: higher when the body is grounded/at-rest (a settled body is a cleaner
    /// grasp target than one in free motion). Relative — a heuristic on the certified read, not a
    /// probability claim.
    pub confidence: f32,
}

impl GraspAffordance {
    /// True only when the affordance is certified-admissible (Thoth may act on it).
    pub fn admissible(&self) -> bool {
        self.verdict == Verdict::Accept
    }

    /// A one-line summary, e.g. "#3 GRASPABLE (accept): size 0.08 <= reach 0.20, impulse 0.012 <= budget 0.10".
    pub fn summary(&self) -> String {
        format!(
            "#{} {} ({}): {}  [conf {:.2}; cites {}]",
            self.id,
            self.kind.as_str().to_uppercase(),
            self.verdict.as_str(),
            self.reason,
            self.confidence,
            self.law,
        )
    }
}

/// Tunables for the affordance gate. Defaults conservative (favour abstain/decline over a wrong
/// "you can grab it"). `hand_reach` / `max_impulse` are RELATIVE (same units as the profile's
/// `char_size` / `momentum`) — see module header; no absolute SI.
#[derive(Debug, Clone)]
pub struct AffordanceConfig {
    /// Maximum object characteristic size Thoth's hand can close around (relative, same units as the
    /// profile's `char_size`). A body larger than this DECLINES graspable (too big — palm it / push).
    pub hand_reach: f32,
    /// Maximum impulse-to-stop Thoth can deliver to arrest a moving body (relative, same units as the
    /// profile's `momentum` |p| = m·|v|). A body whose momentum exceeds this DECLINES graspable (too
    /// much to arrest cleanly) — it may still be Pushable (redirect, not stop).
    pub max_impulse: f32,
    /// Confidence floor: below this, the affordance ABSTAINS even if the gates pass (not enough
    /// certified support to commit to an action).
    pub min_confidence: f32,
}

impl Default for AffordanceConfig {
    fn default() -> Self {
        AffordanceConfig {
            hand_reach: 0.30,
            max_impulse: 0.50,
            min_confidence: 0.3,
        }
    }
}

/// Assess the manual GRASP affordance for one certified object profile — the prescriptive C2-shadow
/// gate. Each gate is an admission clause (abstain-not-assert):
///
///   1. REGIME STABLE: the regime must be one Thoth can act on — `AtRest`, `FreeTranslation`, or
///      `FreeRotation` (a certified free/settled body). A `Forced` or `Abstain` regime ABSTAINS (an
///      actively-forced or unresolved body is not a safe grasp target — honest abstain).
///   2. CLEAN abstain_reason: `NonRigidActuated` ABSTAINS (you do not grab a hand / a deforming body —
///      no single rigid momentum to arrest), `AliasedUnreliable` ABSTAINS (you do not act on an
///      unreliable measurement). The C2-shadow gate made prescriptive.
///   3. SIZE within reach: `char_size <= hand_reach` else DECLINE (too big to close a hand around).
///   4. IMPULSE-TO-STOP within budget: the impulse to arrest the body equals its momentum |p| (the
///      conserved quantity transported into the hand — `fork_preserves_charge`); `momentum <=
///      max_impulse` else DECLINE (too much momentum to arrest cleanly — may still be Pushable).
///
/// A body that passes 1-2 but is in free motion and reach-OK yet over the impulse budget resolves to
/// `Pushable` (redirect, not arrest); a settled (at-rest) body that passes all four is `Graspable`
/// and (since holding then releasing is the conservation continuation) also reports `Droppable`-able.
/// Confidence is higher when the body is grounded (recon-material prior) and at rest.
pub fn assess_grasp_affordance(
    profile: &RigidProfile,
    hand_reach: f32,
    cfg: &AffordanceConfig,
) -> GraspAffordance {
    // Base confidence on the certified read: a grounded, at-rest body is the cleanest grasp target;
    // a free-moving body is harder (the hand must match its motion). Relative heuristic.
    let mut confidence: f32 = 0.5;
    if profile.grounded {
        confidence += 0.2;
    }
    if profile.regime == Regime::AtRest {
        confidence += 0.2;
    } else if profile.regime == Regime::FreeRotation {
        confidence -= 0.1; // a spinner is harder to seize than a translator
    }
    confidence = confidence.clamp(0.0, 1.0);

    // ── GATE 1: regime stable ───────────────────────────────────────────────────────────────────
    if !matches!(
        profile.regime,
        Regime::AtRest | Regime::FreeTranslation | Regime::FreeRotation
    ) {
        return GraspAffordance {
            id: profile.id,
            kind: AffordanceKind::Graspable,
            verdict: Verdict::Abstain,
            law: LAW_GRASP,
            reason: format!(
                "regime {} is not a stable free/settled body (forced or unresolved) — abstain acting",
                profile.regime.as_str()
            ),
            confidence,
        };
    }

    // ── GATE 2: clean abstain_reason (the C2-shadow gate, prescriptive) ──────────────────────────
    match profile.abstain_reason {
        AbstainReason::NonRigidActuated => {
            return GraspAffordance {
                id: profile.id,
                kind: AffordanceKind::Graspable,
                verdict: Verdict::Abstain,
                law: LAW_GRASP,
                reason:
                    "non-rigid/actuated (deforming body — e.g. a hand): no single rigid momentum to arrest — abstain (cannot grab a hand)"
                        .to_string(),
                confidence,
            };
        }
        AbstainReason::AliasedUnreliable => {
            return GraspAffordance {
                id: profile.id,
                kind: AffordanceKind::Graspable,
                verdict: Verdict::Abstain,
                law: LAW_GRASP,
                reason:
                    "aliased/unreliable read (tracking gap or out-of-plane lift): do not act on an unreliable measurement — abstain"
                        .to_string(),
                confidence,
            };
        }
        _ => {}
    }

    // ── GATE 3: size within reach ───────────────────────────────────────────────────────────────
    if profile.char_size > hand_reach {
        return GraspAffordance {
            id: profile.id,
            kind: AffordanceKind::Graspable,
            verdict: Verdict::Decline,
            law: LAW_GRASP,
            reason: format!(
                "char_size {:.4} > hand_reach {:.4} (relative): too big to close a hand around — decline grasp",
                profile.char_size, hand_reach
            ),
            confidence,
        };
    }

    // ── GATE 4: impulse-to-stop within budget (fork_preserves_charge) ────────────────────────────
    // The impulse to arrest the body is exactly its momentum |p| = m·|v| — the conserved quantity the
    // grasp must transport into Thoth's hand. A still body needs ~0 impulse (a clean seize); a fast
    // body needs |p|; over budget => DECLINE graspable, but a reach-OK free-moving body is PUSHABLE.
    let impulse_to_stop = profile.momentum;
    if impulse_to_stop > cfg.max_impulse {
        // Too much momentum to arrest cleanly. If the body is in free motion, a lateral push (redirect)
        // is the admissible affordance instead of an arrest — Pushable, certified by the same law (the
        // push transports a contact impulse, momentum-conserving). If it is somehow at rest with huge
        // |p| (shouldn't happen — momentum ~0 at rest), decline.
        if matches!(profile.regime, Regime::FreeTranslation | Regime::FreeRotation) {
            return GraspAffordance {
                id: profile.id,
                kind: AffordanceKind::Pushable,
                verdict: Verdict::Accept,
                law: LAW_GRASP,
                reason: format!(
                    "impulse-to-stop {:.4} > budget {:.4} but reach-OK and in free motion: a lateral push (redirect, momentum-conserving) is admissible — not an arrest",
                    impulse_to_stop, cfg.max_impulse
                ),
                confidence: (confidence * 0.8).clamp(0.0, 1.0),
            };
        }
        return GraspAffordance {
            id: profile.id,
            kind: AffordanceKind::Graspable,
            verdict: Verdict::Decline,
            law: LAW_GRASP,
            reason: format!(
                "impulse-to-stop {:.4} > budget {:.4} (relative): too much momentum to arrest cleanly — decline grasp",
                impulse_to_stop, cfg.max_impulse
            ),
            confidence,
        };
    }

    // ── CONFIDENCE FLOOR ────────────────────────────────────────────────────────────────────────
    if confidence < cfg.min_confidence {
        return GraspAffordance {
            id: profile.id,
            kind: AffordanceKind::Graspable,
            verdict: Verdict::Abstain,
            law: LAW_GRASP,
            reason: format!(
                "confidence {:.2} below floor {:.2}: not enough certified support to commit — abstain",
                confidence, cfg.min_confidence
            ),
            confidence,
        };
    }

    // ── ADMITTED: a stable, clean, reach-OK, arrestable body is GRASPABLE ────────────────────────
    // An at-rest grasp is also Droppable (hold then release is the conservation continuation); we tag
    // the primary kind Graspable and note the droppable continuation in the reason.
    let droppable_note = if profile.regime == Regime::AtRest {
        " (and droppable once held: release is the free continuation the conservation already certifies)"
    } else {
        ""
    };
    GraspAffordance {
        id: profile.id,
        kind: AffordanceKind::Graspable,
        verdict: Verdict::Accept,
        law: LAW_GRASP,
        reason: format!(
            "size {:.4} <= reach {:.4}, impulse-to-stop {:.4} <= budget {:.4}: a grasp arrests |p| (momentum-conserving contact){}",
            profile.char_size, hand_reach, impulse_to_stop, cfg.max_impulse, droppable_note
        ),
        confidence,
    }
}

/// A one-line scene summary of affordances: counts by kind among the ADMISSIBLE ones, e.g.
/// "2 graspable, 1 pushable; 1 abstained (non-rigid)".
pub fn affordance_summary(affordances: &[GraspAffordance]) -> String {
    use std::collections::BTreeMap;
    let mut admissible: BTreeMap<&'static str, usize> = BTreeMap::new();
    let mut abstained = 0usize;
    let mut declined = 0usize;
    for a in affordances {
        match a.verdict {
            Verdict::Accept => *admissible.entry(a.kind.as_str()).or_default() += 1,
            Verdict::Abstain => abstained += 1,
            Verdict::Decline => declined += 1,
        }
    }
    let mut parts: Vec<String> = admissible.iter().map(|(k, v)| format!("{v} {k}")).collect();
    if abstained > 0 {
        parts.push(format!("{abstained} abstained"));
    }
    if declined > 0 {
        parts.push(format!("{declined} declined"));
    }
    if parts.is_empty() {
        return "no affordances".to_string();
    }
    parts.join(", ")
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::object_intel::{DENSITY_GUESS, MaterialKind};

    /// Build a minimal RigidProfile for the affordance gate tests (mirrors publish.rs::mk_profile).
    fn mk_profile(
        regime: Regime,
        abstain_reason: AbstainReason,
        char_size: f32,
        momentum: f32,
        grounded: bool,
    ) -> RigidProfile {
        RigidProfile {
            id: 1,
            genus: 0,
            silhouette_area: 0.05,
            char_size,
            depth: 0.5,
            volume: 0.025,
            mass: 0.025,
            density: DENSITY_GUESS,
            material: if grounded { MaterialKind::Plastic } else { MaterialKind::Unknown },
            grounded,
            inertia_spin: 0.001,
            vx: 0.0,
            vy: 0.0,
            speed: 0.0,
            momentum,
            ke_lin: 0.0,
            omega: None,
            ang_momentum: None,
            ke_rot: None,
            regime,
            facts: Vec::new(),
            momentum_spread: 0.0,
            ang_spread: None,
            hold_frames: 6,
            abstain_reason,
        }
    }

    /// GRASPABLE when clean: an at-rest, clean-abstain, small, low-momentum body is certified
    /// graspable, citing fork_preserves_charge. Grounded => higher confidence.
    #[test]
    fn graspable_when_clean_regime() {
        let p = mk_profile(Regime::AtRest, AbstainReason::None, 0.08, 0.0, true);
        let a = assess_grasp_affordance(&p, 0.30, &AffordanceConfig::default());
        assert_eq!(a.kind, AffordanceKind::Graspable);
        assert_eq!(a.verdict, Verdict::Accept, "clean at-rest small body => graspable: {}", a.reason);
        assert_eq!(a.law, "ForkRaceFoldVentAreForces.fork_preserves_charge");
        assert!(a.confidence > 0.5, "grounded at-rest => high confidence: {}", a.confidence);
        assert!(a.reason.contains("droppable"), "at-rest grasp notes droppable continuation: {}", a.reason);
    }

    /// ABSTAIN on NonRigidActuated: you cannot grab a hand — a deforming/actuated body has no single
    /// rigid momentum to arrest, so the grasp ABSTAINS (the C2-shadow gate made prescriptive).
    #[test]
    fn abstain_on_non_rigid_actuated() {
        // Regime can be a free one; the abstain_reason NonRigidActuated is the gate that abstains.
        let p = mk_profile(Regime::FreeTranslation, AbstainReason::NonRigidActuated, 0.08, 0.01, false);
        let a = assess_grasp_affordance(&p, 0.30, &AffordanceConfig::default());
        assert_eq!(a.verdict, Verdict::Abstain, "cannot grab a hand: {}", a.reason);
        assert!(a.reason.contains("non-rigid") || a.reason.contains("hand"), "states the reason: {}", a.reason);
    }

    /// ABSTAIN on an unreliable read: AliasedUnreliable abstains (do not act on a bad measurement).
    #[test]
    fn abstain_on_aliased_unreliable() {
        let p = mk_profile(Regime::FreeTranslation, AbstainReason::AliasedUnreliable, 0.08, 0.01, false);
        let a = assess_grasp_affordance(&p, 0.30, &AffordanceConfig::default());
        assert_eq!(a.verdict, Verdict::Abstain, "unreliable read => abstain: {}", a.reason);
    }

    /// ABSTAIN on a forced regime: an actively-forced body is not a stable grasp target.
    #[test]
    fn abstain_on_forced_regime() {
        let p = mk_profile(Regime::Forced, AbstainReason::Forced, 0.08, 0.01, false);
        let a = assess_grasp_affordance(&p, 0.30, &AffordanceConfig::default());
        assert_eq!(a.verdict, Verdict::Abstain, "forced => abstain: {}", a.reason);
    }

    /// DECLINE when too big: a body whose char_size exceeds the hand reach is declined (relative).
    #[test]
    fn decline_when_too_big() {
        let p = mk_profile(Regime::AtRest, AbstainReason::None, 0.60, 0.0, false);
        let a = assess_grasp_affordance(&p, 0.30, &AffordanceConfig::default());
        assert_eq!(a.verdict, Verdict::Decline, "too big => decline: {}", a.reason);
        assert!(a.reason.contains("too big"), "{}", a.reason);
    }

    /// DECLINE when too much impulse: a body at rest (so not pushable) but with momentum over budget
    /// declines. (Constructed: at-rest with a large momentum is degenerate but exercises the gate.)
    #[test]
    fn decline_when_too_much_impulse_at_rest() {
        let cfg = AffordanceConfig { max_impulse: 0.10, ..Default::default() };
        let p = mk_profile(Regime::AtRest, AbstainReason::None, 0.08, 0.50, false);
        let a = assess_grasp_affordance(&p, 0.30, &cfg);
        assert_eq!(a.verdict, Verdict::Decline, "too much momentum, at rest => decline: {}", a.reason);
        assert_eq!(a.kind, AffordanceKind::Graspable);
    }

    /// PUSHABLE when over the impulse budget but in free motion: a fast translating body that is
    /// reach-OK but too energetic to arrest is admissibly PUSHED (redirect), not grasped.
    #[test]
    fn pushable_when_free_and_over_impulse() {
        let cfg = AffordanceConfig { max_impulse: 0.10, ..Default::default() };
        let mut p = mk_profile(Regime::FreeTranslation, AbstainReason::None, 0.08, 0.40, false);
        p.speed = 0.2;
        let a = assess_grasp_affordance(&p, 0.30, &cfg);
        assert_eq!(a.kind, AffordanceKind::Pushable, "free + over-budget => pushable: {}", a.reason);
        assert_eq!(a.verdict, Verdict::Accept, "push is admissible: {}", a.reason);
    }

    #[test]
    fn summary_counts_kinds() {
        let affs = vec![
            assess_grasp_affordance(&mk_profile(Regime::AtRest, AbstainReason::None, 0.08, 0.0, true), 0.30, &AffordanceConfig::default()),
            assess_grasp_affordance(&mk_profile(Regime::FreeTranslation, AbstainReason::NonRigidActuated, 0.08, 0.01, false), 0.30, &AffordanceConfig::default()),
        ];
        let s = affordance_summary(&affs);
        assert!(s.contains("1 graspable"), "{s}");
        assert!(s.contains("1 abstained"), "{s}");
    }
}
